float UniversalModelHotpatcher::bitsPerWeight(QuantType q) const {
    // Approximate bits per weight including GGUF block overhead
    switch (q) {
        case QuantType::F32:    return 32.0f;
        case QuantType::F16:    return 16.0f;
        case QuantType::Q8_0:   return 8.5f;
        case QuantType::Q6_K:   return 6.5625f;
        case QuantType::Q5_K_M: return 5.5f;
        case QuantType::Q4_K_M: return 4.5f;
        case QuantType::Q4_K_S: return 4.25f;
        case QuantType::Q3_K_M: return 3.5f;
        case QuantType::Q2_K:   return 2.5625f; // aggressive compression
        default:                return 16.0f;   // assume F16 fallback
    }
}

uint64_t UniversalModelHotpatcher::estimateQuantizedSize(uint64_t elements, QuantType q) const {
    double bits = (double)bitsPerWeight(q);
    // Size in bytes = (elements * bits_per_weight) / 8
    return (uint64_t)((double)elements * bits / 8.0);
}

