extern "C" {
    int64_t swarm_stream_layer(void* socket, void* data, uint64_t size, uint32_t quant);
    int swarm_receive_header(void* socket, void* header);
}

namespace RawrXD {
namespace Swarm {

SwarmOrchestrator& SwarmOrchestrator::instance() {
    static SwarmOrchestrator inst;
    return inst;
}

SwarmOrchestrator::SwarmOrchestrator() {
    WSADATA wsaData;
    WSAStartup(MAKEWORD(2, 2), &wsaData);
    
    // Generate node ID
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<> dis(0, 15);
    const char* hex = "0123456789abcdef";
    
    m_nodeId = "node-";
    for (int i = 0; i < 16; ++i) {
        m_nodeId += hex[dis(gen)];
    }
}

SwarmOrchestrator::~SwarmOrchestrator() {
    shutdown();
    WSACleanup();
}

bool SwarmOrchestrator::initialize(NodeRole role, const std::string& bindAddr) {
    std::lock_guard<std::mutex> lock(m_mutex);
    m_role = role;
    
    // Create UDP socket for discovery
    m_discoverySock = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (m_discoverySock == INVALID_SOCKET) return false;
    
    int reuse = 1;
    setsockopt(m_discoverySock, SOL_SOCKET, SO_REUSEADDR, (char*)&reuse, sizeof(reuse));
    
    m_bindAddr.sin_family = AF_INET;
    m_bindAddr.sin_port = htons(SWARM_DISCOVERY_PORT);
    inet_pton(AF_INET, bindAddr.c_str(), &m_bindAddr.sin_addr);
    
    if (bind(m_discoverySock, (sockaddr*)&m_bindAddr, sizeof(m_bindAddr)) != 0) {
        closesocket(m_discoverySock);
        return false;
    }
    
    // Join multicast group for LAN discovery
    ip_mreq mreq;
    inet_pton(AF_INET, "239.192.79.46", &mreq.imr_multiaddr); // RAWR multicast
    mreq.imr_interface.s_addr = INADDR_ANY;
    setsockopt(m_discoverySock, IPPROTO_IP, IP_ADD_MEMBERSHIP, (char*)&mreq, sizeof(mreq));
    
    // Create TCP socket for data
    m_dataSock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (m_dataSock == INVALID_SOCKET) return false;
    
    sockaddr_in dataAddr = m_bindAddr;
    dataAddr.sin_port = htons(SWARM_DATA_PORT);
    
    if (bind(m_dataSock, (sockaddr*)&dataAddr, sizeof(dataAddr)) != 0) {
        closesocket(m_dataSock);
        return false;
    }
    
    listen(m_dataSock, 10);
    
    // Start threads
    m_running.store(true);
    m_discoveryThread = std::thread(&SwarmOrchestrator::discoveryListener, this);
    m_dataThread = std::thread(&SwarmOrchestrator::dataListener, this);
    m_heartbeatThread = std::thread(&SwarmOrchestrator::heartbeatThread, this);
    m_inferenceThread = std::thread(&SwarmOrchestrator::inferenceWorker, this);
    
    std::cout << "[SWARM] Node " << m_nodeId << " initialized as " 
              << (role == NodeRole::Coordinator ? "COORDINATOR" : "WORKER") 
              << " on " << bindAddr << "\n";
    return true;
}

void SwarmOrchestrator::shutdown() {
    if (!m_running.exchange(false)) return;
    
    broadcast(0xFFFF, nullptr, 0); // Shutdown signal
    
    closesocket(m_discoverySock);
    closesocket(m_dataSock);
    
    if (m_discoveryThread.joinable()) m_discoveryThread.join();
    if (m_dataThread.joinable()) m_dataThread.join();
    if (m_heartbeatThread.joinable()) m_heartbeatThread.join();
    if (m_inferenceThread.joinable()) m_inferenceThread.join();
    
    std::lock_guard<std::mutex> lock(m_mutex);
    m_nodes.clear();
    std::cout << "[SWARM] Shutdown complete.\n";
}

bool SwarmOrchestrator::distributeModel(const std::string& modelPath, uint32_t totalLayers) {
    if (!isCoordinator()) {
        std::cerr << "[SWARM] Only coordinator can distribute models\n";
        return false;
    }
    
    // Analyze model locally first
    auto& hotpatcher = UniversalModelHotpatcher::instance();
    if (!hotpatcher.analyzeModel(modelPath)) return false;
    
    // Create shards (batches of 4 layers)
    uint32_t numShards = (totalLayers + LAYER_BATCH_SIZE - 1) / LAYER_BATCH_SIZE;
    m_shards.clear();
    
    std::lock_guard<std::mutex> lock(m_mutex);
    
    for (uint32_t i = 0; i < numShards; ++i) {
        LayerShard shard;
        shard.layerStart = i * LAYER_BATCH_SIZE;
        shard.layerEnd = std::min((i + 1) * LAYER_BATCH_SIZE - 1, totalLayers - 1);
        shard.quant = QuantType::Q4_K_M; // Default
        shard.resident = false;
        shard.refCount = 0;
        
        // Assign to best node based on VRAM
        shard.nodeId = selectOptimalNode(i);
        
        m_shards.push_back(shard);
        
        // Notify node to prepare for this shard
        uint32_t msg[3] = {shard.layerStart, shard.layerEnd, static_cast<uint32_t>(shard.quant)};
        sendToNode(shard.nodeId, 0x10, msg, sizeof(msg)); // PrepareShard command
        
        std::cout << "[SWARM] Assigned layers " << shard.layerStart << "-" 
                  << shard.layerEnd << " to node " << shard.nodeId << "\n";
    }
    
    return true;
}

std::string SwarmOrchestrator::selectOptimalNode(uint32_t layerIdx) {
    // Decision tree: Find node with most free VRAM that doesn't have this layer
    std::string bestNode;
    uint64_t maxFreeVRAM = 0;
    
    for (const auto& pair : m_nodes) {
        const auto& node = pair.second;
        if (node.state != NodeState::Active && node.state != NodeState::Overloaded) continue;
        
        // Check if already hosting
        bool hasLayer = std::find(node.hostedLayers.begin(), node.hostedLayers.end(), layerIdx) 
                       != node.hostedLayers.end();
        if (hasLayer) continue;
        
        if (node.freeVRAM > maxFreeVRAM) {
            maxFreeVRAM = node.freeVRAM;
            bestNode = pair.first;
        }
    }
    
    // Fallback to self if no other nodes
    return bestNode.empty() ? m_nodeId : bestNode;
}

bool SwarmOrchestrator::rebalance() {
    if (!isCoordinator()) return false;
    
    std::lock_guard<std::mutex> lock(m_mutex);
    bool rebalanced = false;
    
    // Find overloaded nodes (pressure >= Critical)
    for (auto& shard : m_shards) {
        auto nodeIt = m_nodes.find(shard.nodeId);
        if (nodeIt == m_nodes.end()) continue;
        
        if (nodeIt->second.state == NodeState::Overloaded && shard.refCount == 0) {
            // Migrate to another node
            std::string newNode = selectOptimalNode(shard.layerStart);
            if (newNode != shard.nodeId && !newNode.empty()) {
                std::cout << "[SWARM] Rebalancing layers " << shard.layerStart << "-" 
                          << shard.layerEnd << " from " << shard.nodeId << " to " << newNode << "\n";
                
                migrateLayer(shard.layerStart, shard.nodeId, newNode);
                shard.nodeId = newNode;
                rebalanced = true;
            }
        }
    }
    
    return rebalanced;
}

void SwarmOrchestrator::heartbeatThread() {
    while (m_running.load()) {
        std::this_thread::sleep_for(std::chrono::seconds(5));
        
        // Send heartbeat with current stats
        struct {
            uint64_t freeVRAM;
            uint32_t activeReqs;
            uint8_t pressure; // VRAMPressure enum
        } hb;
        
        auto& hotpatcher = UniversalModelHotpatcher::instance();
        auto budget = hotpatcher.getVRAMBudget();
        hb.freeVRAM = budget.availableRAM; // Use RAM as proxy for VRAM in this context
        hb.pressure = static_cast<uint8_t>(budget.pressure);
        hb.activeReqs = 0; // TODO: track
        
        broadcast(MSG_HEARTBEAT, &hb, sizeof(hb));
        
        // Check for dead nodes
        auto now = std::chrono::steady_clock::now();
        std::lock_guard<std::mutex> lock(m_mutex);
        
        for (auto it = m_nodes.begin(); it != m_nodes.end();) {
            auto lastSeen = std::chrono::duration_cast<std::chrono::seconds>(
                now - it->second.lastHeartbeat).count();
            
            if (lastSeen > 15) { // 15s timeout
                std::cout << "[SWARM] Node " << it->first << " timed out\n";
                if (m_nodeCb) m_nodeCb(it->second, "timeout");
                
                // Redistribute its layers
                for (auto& shard : m_shards) {
                    if (shard.nodeId == it->first) {
                        shard.nodeId = selectOptimalNode(shard.layerStart);
                        // TODO: Trigger recovery load
                    }
                }
                
                it = m_nodes.erase(it);
            } else {
                ++it;
            }
        }
    }
}

void SwarmOrchestrator::discoveryListener() {
    char buffer[1024];
    sockaddr_in from;
    int fromLen = sizeof(from);
    
    while (m_running.load()) {
        int recvLen = recvfrom(m_discoverySock, buffer, sizeof(buffer), 0,
                              (sockaddr*)&from, &fromLen);
        
        if (recvLen > 0) {
            buffer[recvLen] = '\0';
            std::string msg(buffer);
            
            if (msg.find("RAWR_DISCOVER") == 0) {
                // Response with our info
                std::ostringstream response;
                response << "RAWR_NODE|" << m_nodeId << "|" 
                        << (m_role == NodeRole::Coordinator ? "1" : "0") << "|"
                        << UniversalModelHotpatcher::instance().getVRAMBudget().availableRAM;
                
                sendto(m_discoverySock, response.str().c_str(), response.str().length(), 0,
                      (sockaddr*)&from, fromLen);
            }
            else if (msg.find("RAWR_NODE|") == 0) {
                // Another node discovered
                handleNodeJoin(from, msg);
            }
        }
    }
}

void SwarmOrchestrator::dataListener() {
    while (m_running.load()) {
        sockaddr_in client;
        int clientLen = sizeof(client);
        SOCKET clientSock = accept(m_dataSock, (sockaddr*)&client, &clientLen);
        
        if (clientSock == INVALID_SOCKET) continue;
        
        // Handle in new thread or use async I/O
        std::thread([this, clientSock]() {
            char header[32];
            if (swarm_receive_header(reinterpret_cast<void*>(clientSock), header) == 0) {
                uint16_t msgType = *reinterpret_cast<uint16_t*>(header + 4);
                uint64_t payloadSize = *reinterpret_cast<uint64_t*>(header + 8);
                
                std::vector<uint8_t> payload(payloadSize);
                recv(clientSock, reinterpret_cast<char*>(payload.data()), payloadSize, 0);
                
                // Route to handler
                switch (msgType) {
                    case MSG_LAYER_REQUEST:
                        // Worker received request for layer it owns
                        // Stream layer back via swarm_stream_layer ASM
                        break;
                    case MSG_VRAM_PRESSURE:
                        // Update node pressure status
                        break;
                    case MSG_REBALANCE_CMD:
                        // Coordinator ordered layer migration
                        break;
                }
            }
            closesocket(clientSock);
        }).detach();
    }
}

std::string SwarmOrchestrator::getSwarmTopologyJson() const {
    std::lock_guard<std::mutex> lock(m_mutex);
    std::ostringstream oss;
    oss << "{\"self\":\"" << m_nodeId << "\",";
    oss << "\"role\":" << static_cast<int>(m_role) << ",";
    oss << "\"nodes\":[";
    
    bool first = true;
    for (const auto& pair : m_nodes) {
        if (!first) oss << ",";
        first = false;
        const auto& n = pair.second;
        oss << "{\"id\":\"" << n.nodeId << "\",";
        oss << "\"state\":" << static_cast<int>(n.state) << ",";
        oss << "\"vram\":" << n.freeVRAM << ",";
        oss << "\"layers\":[";
        for (size_t i = 0; i < n.hostedLayers.size(); ++i) {
            if (i) oss << ",";
            oss << n.hostedLayers[i];
        }
        oss << "]}";
    }
    oss << "],\"shards\":[";
    
    first = true;
    for (const auto& s : m_shards) {
        if (!first) oss << ",";
        first = false;
        oss << "{\"start\":" << s.layerStart << ",\"end\":" << s.layerEnd 
            << ",\"node\":\"" << s.nodeId << "\",\"quant\":" << static_cast<int>(s.quant) << "}";
    }
    
    oss << "]}";
    return oss.str();
}

